const raw = $('월드컵 입력').first().json;
const body = raw.body || raw;
const { user_id, champion = '', rounds = [], top4 = [] } = body;

const CATS = ['한식','중식','양식','분식','일식','디저트','기타'];
const T = 1.5, EPS = 0.1, K = 7;

// 현재 로짓 맵
const cur = {};
$input.all().forEach(item => {
  if (item.json.category) {
    cur[item.json.category] = {
      logit: item.json.logit ?? 0,
      sample_count: item.json.sample_count ?? 0
    };
  }
});

// 라운드별 델타 계산
const delta = {};
CATS.forEach(c => { delta[c] = 0; });
(rounds || []).forEach(r => {
  if (r.winner_category) delta[r.winner_category] = (delta[r.winner_category] || 0) + 0.5;
  if (r.loser_category)  delta[r.loser_category]  = (delta[r.loser_category]  || 0) - 0.3;
});

// 새 로짓 계산
const now = new Date().toISOString();
const categories_to_upsert = CATS.map(cat => ({
  user_id,
  category: cat,
  logit: Math.round(((cur[cat]?.logit ?? 0) + (delta[cat] || 0)) * 1000) / 1000,
  sample_count: (cur[cat]?.sample_count ?? 0) + (rounds.length > 0 ? 1 : 0),
  updated_at: now
}));

// Softmax 계산 (응답용)
const newLogits = {};
categories_to_upsert.forEach(c => { newLogits[c.category] = c.logit; });
let expSum = 0;
const expMap = {};
CATS.forEach(cat => { expMap[cat] = Math.exp(newLogits[cat] / T); expSum += expMap[cat]; });
const softmax = {};
CATS.forEach(cat => {
  softmax[cat] = Number(((1 - EPS) * expMap[cat] / expSum + EPS / K).toFixed(4));
});
const top_categories = Object.entries(softmax)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([cat]) => cat);

return [{ json: {
  user_id, champion, top4, rounds,
  top_categories, softmax, categories_to_upsert,
  completed: true, created_at: now
} }];

const data = $('월드컵 계산').first().json;
return [{ json: {
  message: `선호도 분석 완료! 👑 ${data.champion}이(가) 우승했어요`,
  top_categories: data.top_categories,
  softmax: data.softmax
} }];
